#include<cstdio>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=40010,BK=256,BB=N/BK+10;int blk,n,a[N],P[N],p,Q,loc[N],ql[BB],qr[BB],L=0,R=1,c[N],s[BB][N];
struct cmp
{
	int p,c;inline cmp(int P=0,int C=0){p=P;c=C;}
	inline bool operator<(const cmp&Q)const{return c==Q.c?p<Q.p:c>Q.c;}
}S[BB][BB],Ans;
int stk[N],top;inline void Clear(){while(top)c[stk[top--]]=0;}
inline void ins(int x){++c[stk[++top]=x];int q=c[x]+(s[R-1][x]-s[L][x]);if(cmp(x,q)<Ans)Ans=cmp(x,q);}
inline int bnd(int k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
int main()
{
	n=read();Q=read();rep(1,n,i)a[i]=P[i]=read(),loc[i]=(i-1)/BK+1;blk=loc[n];
	std::sort(P+1,P+n+1);p=std::unique(P+1,P+n+1)-P-1;rep(1,n,i)a[i]=bnd(a[i]);
	rep(1,blk,i)ql[i]=qr[i-1]+1,qr[i]=i*BK;qr[blk]=n;
	rep(1,blk,L){Ans=cmp(0,0);int r=ql[L]-1;rep(L,blk,R){while(r<qr[R])ins(a[++r]);S[L][R]=Ans;}Clear();}
	rep(1,blk,i){memcpy(s[i],s[i-1],(p+3)<<2);rep(ql[i],qr[i],j)++s[i][a[j]];}
	Ans=cmp(0,0);while(Q--)
	{
		int l=(Ans.p+read()-1)%n+1,r=(Ans.p+read()-1)%n+1;if(l>r){int t=l;l=r;r=t;}
		L=loc[l];R=loc[r];if(L==R){Ans=cmp(0,0);L=0;R=1;rep(l,r,i)ins(a[i]);}
		else{Ans=S[L+1][R-1];rep(l,qr[L],i)ins(a[i]);rep(ql[R],r,i)ins(a[i]);}
		printf("%d\n",Ans.p=P[Ans.p]);Clear();
	}
	
}
